"""HTTP 健康检查脚本"""

import httpx
from loguru import logger
from result import Ok, Err, Result


def health_check(url: str) -> Result[dict, str]:
    """
    检查 HTTP 端点健康状态

    Args:
        url: 要检查的 URL

    Returns:
        Result[dict, str]: 成功返回响应信息，失败返回错误信息
    """
    logger.info(f"开始健康检查: {url}")

    try:
        with httpx.Client(timeout=10.0) as client:
            response = client.get(url)

            if response.status_code == 200:
                logger.success(f"健康检查通过: {url} 返回 200")
                return Ok({
                    "url": url,
                    "status_code": response.status_code,
                    "response_time": response.elapsed.total_seconds()
                })
            else:
                logger.error(f"健康检查失败: {url} 返回 {response.status_code}")
                return Err(f"status_code_{response.status_code}")

    except httpx.TimeoutException:
        logger.error(f"健康检查超时: {url}")
        return Err("timeout")
    except httpx.RequestError as e:
        logger.error(f"请求失败: {url} - {e}")
        return Err(f"request_error: {e}")


def main() -> None:
    """主函数"""
    url = "https://httpbin.org/get"
    result = health_check(url)

    match result:
        case Ok(data):
            logger.info(f"响应时间: {data['response_time']:.3f}秒")
        case Err(error):
            logger.critical(f"检查失败: {error}")
            exit(1)


if __name__ == "__main__":
    main()
